#include <stdio.h>
#include <unistd.h>
#include <string.h>

// ★ Stage 0 — Exemple complet
int main(void) {
    int p[2];
    pipe(p);                                    // ★ p[0]=lecture p[1]=écriture
    int saved_stdout = dup(STDOUT_FILENO);      // ★ copier fd 1 → fd libre (sauvegarde)
    dup2(p[1], STDOUT_FILENO);                  // ★ stdout (fd 1) pointe maintenant vers p[1]
    close(p[1]);                                // ★ fermer l'original p[1] (évite read bloquant)
    printf("hello stdout");                    // ★ va dans le pipe, pas dans le terminal
    fflush(stdout);                             // ★ vider le buffer avant de restaurer
    dup2(saved_stdout, STDOUT_FILENO);          // ★ restaurer stdout → terminal
    close(saved_stdout);                        // ★ fermer la sauvegarde devenue inutile
    char buf[64];
    ssize_t n = read(p[0], buf, sizeof(buf) - 1); // ★ lire ce qui était dans le pipe
    buf[n] = '\0';
    close(p[0]);
    printf("Captured: %s\n", buf);             // ★ afficher dans le vrai stdout
    return 0;
}

